-- M4 Swarm A Task #9: pricing_catalog.
-- Seed catalog used by the estimate engine. product_id is stable (derived from category + description).
-- Seed rows are generated from src/lib/estimate/data/pricingCatalog.json (scripts/gen-pricing-catalog-sql.mjs).
-- Forward-only. Re-running this migration is safe: ON CONFLICT DO NOTHING preserves operator edits.

create table if not exists public.pricing_catalog (
  product_id   text primary key,
  description  text not null,
  unit         text,
  unit_cost    numeric(12, 4) not null default 0,
  category     text not null,
  markup       numeric(6, 4) not null default 1.0,
  active       boolean not null default true,
  metadata     jsonb not null default '{}'::jsonb,
  created_at   timestamptz not null default now(),
  updated_at   timestamptz not null default now()
);

create index if not exists pricing_catalog_category_idx on public.pricing_catalog (category);
create index if not exists pricing_catalog_active_idx on public.pricing_catalog (active);

drop trigger if exists trg_pricing_catalog_set_updated_at on public.pricing_catalog;
create trigger trg_pricing_catalog_set_updated_at
before update on public.pricing_catalog
for each row execute function public.set_updated_at();

-- Seed rows (158 products, sorted by product_id for determinism).
on conflict (product_id) do nothing;
